-- Archive import for Euro 2024. Generated by scripts/generate_archive_import.py
-- Run after supabase/schema.sql and supabase/seed_players.sql.

begin;

on conflict (id) do update set name = excluded.name, year = excluded.year, status = excluded.status;

on conflict (id) do update set
  external_id = excluded.external_id,
  competition_id = excluded.competition_id,
  league = excluded.league,
  home_team = excluded.home_team,
  away_team = excluded.away_team,
  home_logo = excluded.home_logo,
  away_logo = excluded.away_logo,
  handicap = excluded.handicap,
  handicap_is_manual = excluded.handicap_is_manual,
  kickoff_at = excluded.kickoff_at,
  display_time = excluded.display_time,
  display_date = excluded.display_date,
  stadium = excluded.stadium,
  status = excluded.status,
  home_goals = excluded.home_goals,
  away_goals = excluded.away_goals,
  home_scorers = excluded.home_scorers,
  away_scorers = excluded.away_scorers,
  live_time_text = excluded.live_time_text,
  is_hot = excluded.is_hot,
  last_synced_at = excluded.last_synced_at,
  odds_updated_at = excluded.odds_updated_at,
  match_type = excluded.match_type,
  match_group = excluded.match_group;

on conflict (match_id, player_id) do update set
  id = excluded.id,
  competition_id = excluded.competition_id,
  choice = excluded.choice,
  hope_star = excluded.hope_star,
  updated_at = now();

on conflict (prediction_id) do update set
  competition_id = excluded.competition_id,
  match_id = excluded.match_id,
  player_id = excluded.player_id,
  status = excluded.status,
  penalty_vnd = excluded.penalty_vnd,
  settled_at = now();

commit;

